import request from '@/utils/request'

// 档案数据管理
const profile = {
  // 获取完整档案数据
  getData() {
    return request.get('/api/v1/users/profile/data/')
  },

  // 获取简历完整度（保留特殊接口）
  getCompleteness() {
    console.log('获取简历完整度')
    return request.get('/api/v1/users/profile/completeness/')
      .then(response => {
        console.log('Completeness API response:', response)
        return response
      })
  },

  // 更新模块数据
  updateModule(type, data) {
    console.log('更新模块数据:', { type, data })
    const id = data.id

    if (id) {
      // 编辑现有数据
      return request({
        url: `/api/v1/users/profile/${type}/${id}/`,
        method: 'put',
        data
      })
    } else {
      // 新增数据
      return request({
        url: `/api/v1/users/profile/${type}/`,
        method: 'post',
        data
      })
    }
  },

  // 删除模块项目
  deleteModuleItem(type, id) {
    return request({
      url: `/api/v1/users/profile/${type}/${id}/`,
      method: 'delete'
    })
  },

  // 特殊接口保持不变
  uploadAvatar(formData) {
    return request({
      url: '/api/v1/users/profile/avatar/upload/',
      method: 'post',
      headers: { 'Content-Type': 'multipart/form-data' },
      data: formData
    })
  },

  uploadBackground(formData) {
    return request({
      url: '/api/v1/users/profile/background/upload/',
      method: 'post',
      headers: { 'Content-Type': 'multipart/form-data' },
      data: formData
    })
  },

  // 获取布局配置（保留特殊接口）
  getLayout() {
    return request.get('/api/v1/users/profile/layout/')
  },

  // 更新布局配置（保留特殊接口）
  updateLayout(data) {
    return request({
      url: '/api/v1/users/profile/layout/',
      method: 'put',
      data
    })
  },

  uploadBackground(formData) {
    return request({
      url: '/api/v1/users/profile/background/upload/',
      method: 'post',
      data: formData,
      headers: {
        'Content-Type': 'multipart/form-data'
      }
    })
  }
}

export default profile
